local LFightHudData = LxClass("LFightHudData",nil)
     -- 伤害类型表
-----------------------------------------------------------------
function LFightHudData:LFightHudData(changeType,hurt,delay,floatHurtY)
    self._changeType = changeType
    self._hurt = hurt
    self._delay = delay
    self._floatHurtY = floatHurtY

    if changeType then
        local amageTypeRef = GameTable.BattleDamageTypeRef[changeType]
        if not amageTypeRef then
            if LOG_INFO_ENABLED then
                printInfoNR2("战斗打印：","伤害类型表(CombatDamageTypeRef)不存在配置，refId = " .. changeType)
            end
        end
        self._damageTypeIconName = amageTypeRef and amageTypeRef.name or ""
        self._damageNumType = amageTypeRef and amageTypeRef.numType or ""
    end
end

function LFightHudData:GetChangeType()
    return self._changeType
end
function LFightHudData:GetHurt()
    return self._hurt
end
function LFightHudData:GetDelay()
    return self._delay
end
function LFightHudData:GetFloatHurtY()
    return self._floatHurtY
end
function LFightHudData:GetDamageTypeIconName()
    return self._damageTypeIconName
end

function LFightHudData:GetDamageNumType()
    return self._damageNumType
end

-----------------------------------------------------------------
return LFightHudData